#include <unordered_map>
#include <functional>
#include <string>

enum class InputAction { MOVE_LEFT, MOVE_RIGHT, JUMP, ATTACK, PAUSE };

class InputManager {
    // Eylem → Klavye kodu eşlemesi
    std::unordered_map<InputAction, int> keyBindings_ = {
        {InputAction::MOVE_LEFT, KEY_A},
        {InputAction::MOVE_RIGHT, KEY_D},
        {InputAction::JUMP, KEY_SPACE},
        {InputAction::ATTACK, KEY_J},
        {InputAction::PAUSE, KEY_ESCAPE}
    };

    std::unordered_map<int, bool> currentKeys_, previousKeys_;

public:
    void update() {
        previousKeys_ = currentKeys_;
        // Platform-specific key state polling
        for (auto& [action, key] : keyBindings_)
            currentKeys_[key] = IsKeyDown(key);
    }

    bool isHeld(InputAction action) {
        return currentKeys_[keyBindings_[action]];
    }

    bool isPressed(InputAction action) {  // Bu frame basıldı mı?
        int key = keyBindings_[action];
        return currentKeys_[key] && !previousKeys_[key];
    }

    bool isReleased(InputAction action) {
        int key = keyBindings_[action];
        return !currentKeys_[key] && previousKeys_[key];
    }

    void rebind(InputAction action, int newKey) {
        keyBindings_[action] = newKey;
        // Kaydet: settings dosyasına yaz
    }
};
```

